def similar_elements(test_tup1, test_tup2):
    result = []
    for item in test_tup1:
        for item2 in test_tup2:
            if item == item2:
                already_in = False
                for existing in result:
                    if existing == item:
                        already_in = True
                        break
                if not already_in:
                    result.append(item)
    return tuple(result)

def find_Rotations(s):
    n = len(s)
    for i in range(1, n + 1):
        rotated = ""
        for j in range(n):
            rotated += s[(i + j) % n]
        if rotated == s:
            return i
    return n

