def max_sub_array_sum_repeated(a, n, k):
    extended = []
    for _ in range(k):
        for item in a:
            extended.append(item)
    total_len = n * k
    max_sum = extended[0]
    for i in range(total_len):
        current_sum = 0
        for j in range(i, total_len):
            current_sum += extended[j]
            if current_sum > max_sum:
                max_sum = current_sum
    return max_sum

def k_smallest_pairs(nums1, nums2, k):
    all_pairs = []
    for x in nums1:
        for y in nums2:
            all_pairs.append([x, y])
    n = len(all_pairs)
    for i in range(n):
        for j in range(n - i - 1):
            if all_pairs[j][0] + all_pairs[j][1] > all_pairs[j+1][0] + all_pairs[j+1][1]:
                all_pairs[j], all_pairs[j+1] = all_pairs[j+1], all_pairs[j]
    return all_pairs[:k]

def amicable_numbers_sum(limit):
    def sum_divisors(n):
        total = 1
        for i in range(2, n):
            if n % i == 0:
                total += i
        return total

    result = 0
    for n in range(2, limit + 1):
        s = sum_divisors(n)
        if s != n and s <= limit:
            if sum_divisors(s) == n:
                result += n
    return result

def is_not_prime(n):
    if n <= 1:
        return True
    if n == 2:
        return False
    if n == 3:
        return False
    if n == 5:
        return False
    if n == 7:
        return False
    if n % 2 == 0:
        return True
    if n % 3 == 0:
        return True
    if n % 5 == 0:
        return True
    i = 7
    while i * i <= n:
        if n % i == 0:
            return True
        if n % (i + 4) == 0:
            return True
        if n % (i + 6) == 0:
            return True
        i += 10
    return False

def median_numbers(a, b, c):
    if a <= b <= c or c <= b <= a:
        return float(b)
    elif b <= a <= c or c <= a <= b:
        return float(a)
    elif a <= c <= b or b <= c <= a:
        return float(c)
    elif a == b and b == c:
        return float(a)
    elif a == b:
        return float(a)
    elif b == c:
        return float(b)
    elif a == c:
        return float(a)
