def remove_Occ(s, ch):
    if ch not in s:
        return s
    first_idx = -1
    for i in range(len(s)):
        if s[i] == ch:
            first_idx = i
            break
    last_idx = -1
    for i in range(len(s)):
        if s[i] == ch:
            last_idx = i
    result = ""
    for i in range(len(s)):
        if i == first_idx or i == last_idx:
            continue
        result += s[i]
    return result

