def comb_sort(alist):
    gap = len(alist)
    shrink = 1.3
    sorted_flag = False
    while not sorted_flag:
        gap = int(gap / shrink)
        if gap <= 1:
            gap = 1
            sorted_flag = True
        swapped = False
        for i in range(len(alist) - gap):
            if alist[i] > alist[i + gap]:
                temp = alist[i]
                alist[i] = alist[i + gap]
                alist[i + gap] = temp
                swapped = True
                sorted_flag = False
        if not swapped and gap == 1:
            sorted_flag = True
    return alist

def power(a, b):
    if b == 0:
        return 1
    if b == 1:
        return a
    if b == 2:
        return a * a
    if b == 3:
        return a * a * a
    if a == 0:
        return 0
    if a == 1:
        return 1
    result = 1
    for _ in range(b):
        result *= a
    return result

def babylonian_squareroot(number):
    MAX_ITER = 10000
    TOLERANCE = 0.0000001
    if number < 0:
        return -1
    if number == 0:
        return 0
    x = number / 2.0
    for _ in range(MAX_ITER):
        x_new = (x + number / x) / 2.0
        if abs(x_new - x) < TOLERANCE:
            break
        x = x_new
    return x

def smallest_num(s):
