    for i in range(len(s)):
        if s[i] < current_min:
            current_min = s[i]
    return current_min

def volume_sphere(r):
    pi_value = 3.14159
    volume = 4 * (1 / 3) * pi_value * r * r * r
    return round(volume, 2)

def zero_count(l):
    zero_cnt = 0
    non_zero_cnt = 0
    for item in l:
        if item == 0:
            zero_cnt += 1
        else:
            non_zero_cnt += 1
    return zero_cnt / non_zero_cnt
